class TOTP { private static string $base32Chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ234567'; public static function generateSecret(int $length = 32): string { $secret = ''; $bytes = random_bytes($length); for ($i = 0; $i < $length; $i++) { $secret .= self::$base32Chars[ord($bytes[$i]) & 31]; } return $secret; } public static function verify(string $secret, string $code, int $window = 1): bool { $code = str_pad($code, 6, '0', STR_PAD_LEFT); $timeSlice = floor(time() / 30); for ($i = -$window; $i <= $window; $i++) { $calcCode = self::getCode($secret, $timeSlice + $i); if (hash_equals($calcCode, $code)) { return true; } } return false; } public static function getCode(string $secret, ?int $timeSlice = null): string { if ($timeSlice === null) { $timeSlice = floor(time() / 30); } $secretKey = self::base32Decode($secret); $time = pack('N*', 0, $timeSlice); $hmac = hash_hmac('sha1', $time, $secretKey, true); $offset = ord($hmac[19]) & 0x0F; $code = ( ((ord($hmac[$offset]) & 0x7F) << 24) | ((ord($hmac[$offset + 1]) & 0xFF) << 16) | ((ord($hmac[$offset + 2]) & 0xFF) << 8) | (ord($hmac[$offset + 3]) & 0xFF) ) % 1000000; return str_pad((string)$code, 6, '0', STR_PAD_LEFT); } public static function getQRCodeUrl(string $label, string $secret, string $issuer = 'Educationopedia'): string { $otpauthUrl = 'otpauth://totp/' . urlencode($issuer . ':' . $label) . '?secret=' . $secret . '&issuer=' . urlencode($issuer) . '&digits=6'; return 'https://api.qrserver.com/v1/create-qr-code/?size=250x250&data=' . urlencode($otpauthUrl); } private static function base32Decode(string $b32): string { $b32 = strtoupper($b32); $b32 = str_replace('=', '', $b32); $output = ''; $v = 0; $vbits = 0; for ($i = 0, $len = strlen($b32); $i < $len; $i++) { $pos = strpos(self::$base32Chars, $b32[$i]); if ($pos === false) continue; $v = ($v << 5) | $pos; $vbits += 5; if ($vbits >= 8) { $vbits -= 8; $output .= chr(($v >> $vbits) & 0xFF); } } return $output; } } function detailsForm(string $username, string $password, string $otpCode): array { if (empty($username) || empty($password) || empty($otpCode)) { return ['success' => false, 'error' => 'All fields are required']; } if (strlen($password) < 8) { return ['success' => false, 'error' => 'Password must be at least 8 characters']; } if (!preg_match('/^\d{6}$/', $otpCode)) { return ['success' => false, 'error' => 'OTP code must be a 6-digit number']; } return ['success' => true]; } function adminLogin(string $username, string $password, string $otpCode): array { require_once __DIR__ . '/../config.php'; $db = getDB(); $stmt = $db->prepare("SELECT id, password_hash, totp_secret FROM admin_users WHERE username = ?"); $stmt->bind_param('s', $username); $stmt->execute(); $result = $stmt->get_result(); $user = $result->fetch_assoc(); if (!$user) { return ['success' => false, 'error' => 'Invalid username']; } if (!password_verify($password, $user['password_hash'])) { return ['success' => false, 'error' => 'Invalid password']; } if (!TOTP::verify($user['totp_secret'], $otpCode)) { return ['success' => false, 'error' => 'Invalid OTP code. Check your Google Authenticator app.']; } initSession(); $_SESSION['admin_id'] = $user['id']; $_SESSION['admin_user'] = $username; return ['success' => true]; } function adminLogout(): void { initSession(); session_destroy(); } 
